# 用 while 数到10
count = 1
while count <= 10:
    print(count)
    count += 1  # 等同于 count = count + 1

# 猜数字游戏
secret = 7
while True:
    guess = int(input("猜一个1-10的数字："))
    if guess == secret:
        print("猜对了！")
        break   # 跳出循环
    elif guess < secret:
        print("太小了")
    else:
        print("太大了")
